const ComponentProcessor = require('../../../../../src/lib/processors/inject/ComponentProcessor'); // Singleton
const Component = require('../../../../../src/lib/annotations/inject/Component');
const { expect } = require('chai');

describe('@Component Processor', () => {
  let mockCtx;

  beforeEach(() => {
    // Mock context simulates DI container and logging
    mockCtx = {
      container: {
        register: (name, instance) => {
          // Save registration info for assertions
          mockCtx.registered = { name, instance };
        }
      },
      config: { baseDir: __dirname },
      log: []  // Ensure log is an array to avoid TypeError
    };
  });

  it('should handle processScan without errors', () => {
    const meta = {
      annotation: new Component(),
      className: 'TestService',
      classRef: class TestService {},
    };

    // ⚡ Use Singleton directly
    expect(() => ComponentProcessor.processScan(meta, mockCtx)).to.not.throw();
  });

  it('should register component during processInstantiate', () => {
    const meta = {
      annotation: new Component(),
      className: 'TestService',
      classRef: class TestService {},
    };

    // ⚡ Use Singleton directly
    ComponentProcessor.processInstantiate(meta, mockCtx);

    // Verify the component was registered in the container
    expect(mockCtx.registered).to.exist;
    expect(mockCtx.registered.name).to.equal('TestService');
    expect(typeof mockCtx.registered.instance).to.equal('object');
    expect(mockCtx.registered.instance).to.be.instanceOf(meta.classRef);
  });
});
